const task = $.input.codingTask;
const lang = $.input.language || 'JavaScript';
const difficulty = $.input.difficulty || 'intermediate';

let prompt = 'You are an expert programmer and coding instructor. Generate clear, well-documented code examples for the following task.\n\n';
prompt += 'CODING TASK: ' + task + '\n';
prompt += 'LANGUAGE: ' + lang + '\n';
prompt += 'DIFFICULTY: ' + difficulty + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Generate 2-3 code examples that progressively demonstrate the concept\n';
prompt += '- Include inline comments explaining key parts\n';
prompt += '- Add a brief explanation before each example\n';
prompt += '- Include common pitfalls or best practices\n';
prompt += '- For ' + difficulty + ' level: adjust complexity accordingly\n';
prompt += '- Keep each code block under 2500 characters\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "descriptive title",\n';
prompt += '  "overview": "brief overview of the concept",\n';
prompt += '  "examples": [\n';
prompt += '    {\n';
prompt += '      "name": "Example 1: Basic usage",\n';
prompt += '      "explanation": "what this example demonstrates",\n';
prompt += '      "code": "the code with comments",\n';
prompt += '      "output": "expected output if applicable"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "bestPractices": ["practice 1", "practice 2"],\n';
prompt += '  "commonPitfalls": ["pitfall 1", "pitfall 2"],\n';
prompt += '  "furtherReading": ["topic or resource 1"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.codingTask, overview: '', examples: [{ name: 'Code', explanation: '', code: raw.slice(0, 2500), output: '' }], bestPractices: [], commonPitfalls: [], furtherReading: [] }; }

const ai = $.steps.parseAI.output;
const lang = $.input.language || 'JavaScript';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: (ai.title || $.input.codingTask).slice(0, 150), emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Language:* ' + lang + ' | *Difficulty:* ' + ($.input.difficulty || 'intermediate') } });

if (ai.overview) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.overview.slice(0, 2900) } });
}
blocks.push({ type: 'divider' });

(ai.examples || []).forEach((ex, i) => {
  if (ex.name) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + ex.name + '*' } });
  }
  if (ex.explanation) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ex.explanation.slice(0, 1500) } });
  }
  if (ex.code) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '```' + ex.code.slice(0, 2800) + '```' } });
  }
  if (ex.output) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '_Output:_ `' + ex.output.slice(0, 500) + '`' } });
  }
  blocks.push({ type: 'divider' });
});

if (ai.bestPractices && ai.bestPractices.length > 0) {
  let bpText = ':white_check_mark: *Best Practices:*\n';
  ai.bestPractices.forEach((p, i) => { bpText += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: bpText.slice(0, 2900) } });
}

if (ai.commonPitfalls && ai.commonPitfalls.length > 0) {
  let cpText = ':warning: *Common Pitfalls:*\n';
  ai.commonPitfalls.forEach((p, i) => { cpText += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: cpText.slice(0, 2900) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Generated with Claude AI | One CLI' }] });

const fallback = 'Code Snippets: ' + (ai.title || $.input.codingTask) + ' (' + lang + ')';
return { blocks, fallback };
